mapper.select:
SELECT dept_id AS deptId, JSBJ AS jsbj, CBJTHBJ AS cbjthbj, COUNT(*) AS bs, COUNT(DISTINCT DJXH) AS hs, SUM(YBTSE) AS ybtse, SUM(CBJJE) AS cbjje, SUM(JCGHJE) AS jcghje FROM gh_jf
AND dept_id = #{req.deptId} AND NSRMC LIKE CONCAT('%', #{req.nsrmc}, '%') AND ZGSWJ_DM = #{req.zgswjDm} AND JSBJ = #{req.jsbj} AND ZSPM_DM = #{req.zspmDm}
GROUP BY dept_id, JSBJ, CBJTHBJ
